from __future__ import annotations

"""01 데이터 구조 분석 노드.

이 파일은 00번 노드가 만든 rows/columns 데이터를 훑어서
어떤 컬럼이 숫자 metric인지, 어떤 컬럼이 날짜 축인지, 어떤 컬럼이 범주/상태인지
추정합니다. 이 분석 결과는 02번 요소 추천과 03번 리포트 계획 생성의 근거가 됩니다.
"""

import json
import re
from copy import deepcopy
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, Output
from lfx.schema.data import Data


# 컬럼명에 자주 등장하는 단어를 보고 의미를 추정하기 위한 정규식입니다.
# 예: `DATE`, `기준일`은 시간축 후보, `STATUS`, `오류`는 상태/예외 후보가 됩니다.
DATE_RE = re.compile(r"date|dt|time|day|week|month|year|날짜|일자|기준일|월|주차|시간", re.I)
ID_RE = re.compile(r"(^|_)(id|key|code|no|seq)($|_)|코드|번호|식별", re.I)
DELTA_RE = re.compile(r"delta|diff|change|증감|변화|차이|gap|rate|ratio|percent|%|율", re.I)
STATUS_RE = re.compile(r"status|state|flag|error|warning|issue|risk|상태|오류|경고|이상|위험", re.I)


def build_data_profile(analysis_payload: Any, question: str = "") -> dict[str, Any]:
    """입력 payload를 분석해서 리포트 계획에 필요한 데이터 프로파일을 만듭니다.

    주요 결과:
    - `columns`: 각 컬럼의 타입 추정 결과와 샘플 값
    - `column_groups`: 숫자/범주/날짜/상태 컬럼 묶음
    - `question_hints`: 질문 문구에서 요약/비교/추이 등의 의도 힌트
    - `report_signals`: 어떤 리포트 요소가 필요할지 판단하는 신호
    """

    payload = _payload(analysis_payload)
    request = _dict(payload.get("request"))
    resolved_question = str(question or "").strip() or str(request.get("question") or payload.get("question") or "").strip()
    view_request = str(request.get("view_request") or payload.get("view_request") or "").strip()
    intent_text = " ".join(text for text in (resolved_question, view_request) if text)
    api = _dict(payload.get("api_response")) or payload
    data = _dict(api.get("data")) or _dict(payload.get("data"))
    rows = _rows(data.get("rows")) or _rows(api.get("rows")) or _rows(payload.get("rows"))
    columns = _strings(data.get("columns")) or _strings(api.get("columns")) or _columns_from_rows(rows)
    row_count = _int(data.get("row_count"), _int(api.get("row_count"), len(rows)))
    data_ref = _dict(data.get("data_ref")) or _dict(api.get("data_ref"))
    warnings = _unique([*_list(payload.get("warnings")), *_list(api.get("warnings"))])
    errors = _unique([*_list(payload.get("errors")), *_list(api.get("errors"))])
    data_views = _list(payload.get("data_views"))
    available_data_views = _list(payload.get("available_data_views"))
    relationship_candidates = _list(payload.get("relationship_candidates"))
    # 너무 많은 row를 모두 훑으면 Langflow 실행이 무거워질 수 있어 앞 200개만 샘플로 분석합니다.
    column_profiles = [_profile_column(column, rows[:200]) for column in columns]
    groups = _groups(column_profiles)
    hints = _hints(intent_text)
    shape = {
        "row_count": row_count,
        "preview_row_count": len(rows),
        "column_count": len(columns),
        "data_is_preview": bool(data.get("data_is_preview") or api.get("data_is_preview") or row_count > len(rows)),
        "data_ref_present": bool(data_ref),
        "data_ref_loaded": bool(data.get("data_ref_loaded") or api.get("data_ref_loaded")),
        "data_ref_load_mode": data.get("data_ref_load_mode") or api.get("data_ref_load_mode") or "",
        "active_data_view_id": data.get("data_view_id") or request.get("active_data_view_id") or "",
        "active_data_view_strategy": data.get("strategy") or "",
    }
    signals = {
        "has_numeric_metrics": bool(groups["numeric_columns"]),
        "has_dimensions": bool(groups["dimension_columns"]),
        "has_time_axis": bool(groups["time_columns"]),
        "has_delta_or_rate": bool(groups["delta_columns"]),
        "has_status_or_exception": bool(groups["status_columns"] or warnings or errors),
        "looks_like_query_result": hints["detail"] or (row_count > 0 and not hints["summary"]),
        "looks_like_aggregate_result": row_count <= 50 and bool(groups["numeric_columns"]),
        "needs_preview_warning": bool(shape["data_is_preview"] or warnings or errors),
    }
    return {
        "profile_version": "html-report-data-profile-v1",
        "question": resolved_question,
        "view_request": view_request,
        "intent_text": intent_text,
        "shape": shape,
        "columns": column_profiles,
        "column_groups": groups,
        "question_hints": hints,
        "report_signals": signals,
        "available_datasets": _list(payload.get("available_datasets")),
        "available_data_views": available_data_views,
        "relationship_candidates": relationship_candidates,
        "data_view_profiles": [_profile_data_view(view) for view in data_views[:8] if isinstance(view, dict)],
        "data_ref": data_ref,
        "warnings": warnings,
        "errors": errors,
        "preview_rows": deepcopy(rows[:10]),
    }


def _profile_data_view(view: dict[str, Any]) -> dict[str, Any]:
    """여러 데이터셋/결합 view를 LLM이 이해할 수 있도록 작게 요약합니다."""

    rows = _rows(view.get("rows"))
    columns = _strings(view.get("columns")) or _columns_from_rows(rows)
    profiles = [_profile_column(column, rows[:120]) for column in columns]
    return {
        "data_view_id": str(view.get("data_view_id") or ""),
        "label": str(view.get("label") or view.get("data_view_id") or ""),
        "strategy": str(view.get("strategy") or "select"),
        "source_dataset_ids": _strings(view.get("source_dataset_ids")),
        "join_keys": _strings(view.get("join_keys")),
        "shape": {
            "row_count": _int(view.get("row_count"), len(rows)),
            "preview_row_count": len(rows),
            "column_count": len(columns),
        },
        "columns": [
            {
                "name": item.get("name"),
                "inferred_type": item.get("inferred_type"),
                "semantic_hint": item.get("semantic_hint", ""),
                "sample_values": _list(item.get("sample_values"))[:3],
                "top_values": _list(item.get("top_values"))[:8],
                "numeric_stats": _dict(item.get("numeric_stats")),
            }
            for item in profiles
        ],
        "column_groups": _groups(profiles),
        "preview_rows": deepcopy(rows[:3]),
    }


def _profile_column(column: str, rows: list[dict[str, Any]]) -> dict[str, Any]:
    """한 컬럼의 값 분포를 보고 타입, 결측 수, 샘플 값, 숫자 통계를 계산합니다."""

    values = [row.get(column) for row in rows]
    non_empty = [value for value in values if value not in (None, "", [], {})]
    unique_values = _unique(non_empty)
    inferred = _infer_type(column, non_empty, unique_values)
    numeric_values = [number for number in (_number(value) for value in non_empty) if number is not None]
    result: dict[str, Any] = {
        "name": column,
        "inferred_type": inferred,
        "non_empty_count": len(non_empty),
        "null_count": len(values) - len(non_empty),
        "unique_count": len(unique_values),
        "sample_values": _sample(non_empty),
        "top_values": _top_values(non_empty),
        "is_metric_candidate": inferred == "numeric",
        "is_dimension_candidate": inferred in {"dimension", "id", "status"},
        "is_time_candidate": inferred == "time",
        "is_text_candidate": inferred == "text",
    }
    if DELTA_RE.search(column):
        # 증감률/변화량처럼 보이는 컬럼은 카드나 해석에서 별도로 활용할 수 있게 표시합니다.
        result["semantic_hint"] = "delta_or_rate"
    if STATUS_RE.search(column):
        # 오류/경고/상태 컬럼은 예외 테이블 후보가 됩니다.
        result["semantic_hint"] = "status_or_exception"
    if numeric_values:
        result["numeric_stats"] = {
            "min": min(numeric_values),
            "max": max(numeric_values),
            "sum": sum(numeric_values),
            "avg": sum(numeric_values) / len(numeric_values),
        }
    return result


def _infer_type(column: str, values: list[Any], unique_values: list[Any]) -> str:
    """컬럼명과 실제 값 샘플을 함께 보고 간단한 타입을 추정합니다."""

    if not values:
        return "empty"
    if DATE_RE.search(column) or _date_ratio(values) >= 0.6:
        return "time"
    if _numeric_ratio(values) >= 0.8:
        return "numeric"
    if STATUS_RE.search(column):
        return "status"
    if ID_RE.search(column) and len(unique_values) >= min(len(values), 20):
        return "id"
    if sum(len(str(value)) for value in values) / max(len(values), 1) >= 50:
        return "text"
    return "dimension"


def _groups(column_profiles: list[dict[str, Any]]) -> dict[str, list[str]]:
    """컬럼별 프로파일을 숫자/범주/날짜/상태 같은 그룹으로 다시 묶습니다."""

    groups = {
        "numeric_columns": [],
        "dimension_columns": [],
        "time_columns": [],
        "text_columns": [],
        "id_columns": [],
        "status_columns": [],
        "delta_columns": [],
    }
    for profile in column_profiles:
        name = str(profile.get("name") or "")
        inferred = profile.get("inferred_type")
        if inferred == "numeric":
            groups["numeric_columns"].append(name)
        if inferred in {"dimension", "status"}:
            groups["dimension_columns"].append(name)
        if inferred == "time":
            groups["time_columns"].append(name)
        if inferred == "text":
            groups["text_columns"].append(name)
        if inferred == "id":
            groups["id_columns"].append(name)
        if inferred == "status" or profile.get("semantic_hint") == "status_or_exception":
            groups["status_columns"].append(name)
        if profile.get("semantic_hint") == "delta_or_rate":
            groups["delta_columns"].append(name)
    return groups


def _hints(question: str) -> dict[str, bool]:
    """사용자 질문 문장에 포함된 단어로 리포트 의도를 추정합니다."""

    text = str(question or "").lower()
    return {
        "summary": _has(text, ["요약", "현황", "핵심", "주요", "지표", "카드", "summary", "overview", "kpi", "card"]),
        "comparison": _has(text, ["비교", "차이", "별", "막대", "그래프", "차트", "compare", "comparison", "versus", "vs", "bar", "chart"]),
        "trend": _has(text, ["추이", "변화", "기간", "날짜", "일별", "주별", "월별", "시계열", "선그래프", "선 그래프", "라인", "trend", "daily", "weekly", "monthly", "line", "timeline"]),
        "ranking": _has(text, ["상위", "하위", "top", "bottom", "순위", "랭킹", "가장 많은", "가장 적은"]),
        "detail": _has(text, ["상세", "목록", "리스트", "표", "테이블", "상세표", "row", "raw", "table", "원본", "그대로", "보여줘", "조회"]),
        "exception": _has(text, ["이상", "문제", "경고", "오류", "리스크", "초과", "미달", "exception", "error", "warning", "risk"]),
        "report": _has(text, ["리포트", "보고서", "html", "dashboard", "대시보드", "공유"]),
    }


def _has(text: str, needles: list[str]) -> bool:
    """문장 안에 후보 단어 중 하나라도 포함되어 있는지 확인합니다."""

    return any(needle.lower() in text for needle in needles)


def _payload(value: Any) -> dict[str, Any]:
    """Langflow Data/Message/dict/JSON 문자열을 일반 dict로 맞춥니다."""

    if isinstance(value, dict):
        return deepcopy(value)
    data = getattr(value, "data", None)
    if isinstance(data, dict):
        return deepcopy(data)
    text = getattr(value, "text", None) or getattr(value, "content", None)
    if isinstance(text, str) and text.strip():
        try:
            parsed = json.loads(text)
        except Exception:
            return {"text": text}
        return deepcopy(parsed) if isinstance(parsed, dict) else {"text": text}
    return {}


def _rows(value: Any) -> list[dict[str, Any]]:
    """dict row 목록만 안전하게 복사해서 반환합니다."""

    return [deepcopy(row) for row in value if isinstance(row, dict)] if isinstance(value, list) else []


def _columns_from_rows(rows: list[dict[str, Any]]) -> list[str]:
    """rows에 등장한 컬럼명을 중복 없이 수집합니다."""

    columns: list[str] = []
    for row in rows:
        for key in row:
            text = str(key)
            if text not in columns:
                columns.append(text)
    return columns


def _strings(value: Any) -> list[str]:
    """문자열 목록을 정리하고 중복을 제거합니다."""

    if not isinstance(value, list):
        return []
    result = []
    for item in value:
        text = str(item or "").strip()
        if text and text not in result:
            result.append(text)
    return result


def _dict(value: Any) -> dict[str, Any]:
    """dict가 아닌 값은 빈 dict로 바꿔 뒤 로직을 단순하게 만듭니다."""

    return deepcopy(value) if isinstance(value, dict) else {}


def _list(value: Any) -> list[Any]:
    """list/tuple/set이면 list로 바꾸고, 아니면 빈 list를 반환합니다."""

    return list(value) if isinstance(value, (list, tuple, set)) else []


def _int(value: Any, fallback: int = 0) -> int:
    """문자열/실수를 정수로 바꾸되 실패하면 fallback을 반환합니다."""

    if isinstance(value, bool):
        return fallback
    if isinstance(value, int):
        return value
    if isinstance(value, float) and value == value:
        return int(value)
    try:
        return int(str(value).replace(",", ""))
    except Exception:
        return fallback


def _number(value: Any) -> float | None:
    """값이 숫자로 해석 가능하면 float로, 아니면 None으로 반환합니다."""

    if isinstance(value, bool):
        return None
    if isinstance(value, (int, float)) and value == value:
        return float(value)
    text = str(value or "").strip().replace(",", "").replace("%", "")
    try:
        return float(text) if text else None
    except Exception:
        return None


def _numeric_ratio(values: list[Any]) -> float:
    """값 목록 중 숫자로 해석 가능한 값의 비율을 계산합니다."""

    return sum(1 for value in values if _number(value) is not None) / len(values) if values else 0.0


def _date_ratio(values: list[Any]) -> float:
    """값 목록 중 날짜처럼 보이는 값의 비율을 계산합니다."""

    return sum(1 for value in values if _looks_like_date(value)) / len(values) if values else 0.0


def _looks_like_date(value: Any) -> bool:
    """간단한 날짜 형식인지 확인합니다. 예: 2026-06-20, 20260620."""

    text = str(value or "").strip()
    return bool(re.match(r"^\d{4}[-/]\d{1,2}([-/]\d{1,2})?", text) or re.match(r"^\d{6}(\d{2})?$", text))


def _sample(values: list[Any], limit: int = 5) -> list[Any]:
    """중복을 제거한 샘플 값을 최대 limit개 반환합니다."""

    return _unique(values)[:limit]


def _top_values(values: list[Any], limit: int = 12) -> list[dict[str, Any]]:
    """범주/상태/코드 값의 빈도를 LLM이 이해하기 쉬운 형태로 요약합니다.

    예를 들어 `ALERT_LEVEL` 컬럼에 HIGH/WARN/NORMAL 값이 있으면
    LLM이 정확한 값 문자열을 사용해 filter_rules나 highlight_rules를 만들 수 있습니다.
    """

    counts: dict[str, dict[str, Any]] = {}
    for value in values:
        if value in (None, "", [], {}):
            continue
        signature = json.dumps(value, ensure_ascii=False, sort_keys=True, default=str)
        if signature not in counts:
            counts[signature] = {"value": deepcopy(value), "count": 0}
        counts[signature]["count"] += 1
    ranked = sorted(counts.values(), key=lambda item: (-int(item["count"]), str(item["value"])))
    return ranked[:limit]


def _unique(values: list[Any]) -> list[Any]:
    """값 목록에서 빈 값과 중복 값을 제거합니다."""

    result: list[Any] = []
    signatures: set[str] = set()
    for value in values:
        if value in (None, "", [], {}):
            continue
        signature = json.dumps(value, ensure_ascii=False, sort_keys=True, default=str)
        if signature not in signatures:
            signatures.add(signature)
            result.append(deepcopy(value))
    return result


class HtmlReportDataProfileBuilder(Component):
    """Langflow 화면에 표시되는 01번 커스텀 컴포넌트 클래스."""

    display_name = "01 데이터 구조 분석"
    description = "리포트에 쓸 컬럼 유형, 숫자/범주/날짜 후보, 데이터 품질 신호를 요약합니다."
    icon = "ScanSearch"
    inputs = [
        DataInput(name="analysis_payload", display_name="요청 데이터", required=True),
    ]
    outputs = [Output(name="data_profile", display_name="데이터 분석 결과", method="build_profile")]

    def build_profile(self) -> Data:
        """00번 요청 데이터를 받아 데이터 분석 결과를 출력합니다."""

        result = build_data_profile(getattr(self, "analysis_payload", None))
        groups = result.get("column_groups") or {}
        self.status = {
            "rows": (result.get("shape") or {}).get("row_count", 0),
            "columns": (result.get("shape") or {}).get("column_count", 0),
            "numeric": len(groups.get("numeric_columns", [])),
            "time": len(groups.get("time_columns", [])),
        }
        return Data(data=result)

from __future__ import annotations

"""03 기본 리포트 계획 노드.

이 파일은 02번에서 추천된 요소를 실제 렌더러가 이해할 수 있는 `report_plan`
형식으로 바꿉니다. 이 계획은 그대로 HTML 렌더링에 사용할 수도 있고,
03a/03b를 거쳐 LLM이 더 풍부하게 보완한 계획으로 바꿀 수도 있습니다.
"""

import json
from copy import deepcopy
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, MessageTextInput, Output
from lfx.schema.data import Data


def build_auto_html_plan(payload_value: Any, data_profile_value: Any, component_catalog_value: Any, max_blocks: Any = "auto") -> dict[str, Any]:
    """요청 데이터, 데이터 프로파일, 요소 카탈로그를 합쳐 기본 report_plan을 만듭니다."""

    payload = _payload(payload_value)
    profile = _payload(data_profile_value)
    catalog = _payload(component_catalog_value)
    request = _dict(payload.get("request"))
    groups = _dict(profile.get("column_groups"))
    shape = _dict(profile.get("shape"))
    recommendations = _prioritize_recommendations(
        _list(catalog.get("recommended_components")),
        _strings(_dict(request.get("visual_request")).get("requested_blocks")),
    )
    max_count, max_count_source = _resolve_max_blocks(max_blocks, request, profile)

    title = _title(request, profile)
    blocks: list[dict[str, Any]] = []
    for recommendation in recommendations:
        # 추천된 component_id를 렌더러가 바로 사용할 block dict로 변환합니다.
        if not isinstance(recommendation, dict):
            continue
        block_id = str(recommendation.get("component_id") or "")
        block = _block_from_recommendation(block_id, recommendation, groups, shape)
        if block and not any(existing.get("block_id") == block_id for existing in blocks):
            blocks.append(block)
        if len(blocks) >= max_count:
            break

    if not blocks:
        # 추천 결과가 비어도 최소한 제목과 상세표는 나오도록 fallback 계획을 둡니다.
        blocks = [
            {"block_id": "report_header", "title": title},
            {"block_id": "detail_data_table", "title": "상세 데이터", "columns": _display_columns(groups, limit=12), "limit": 50},
        ]

    plan = {
        "plan_version": "html-report-plan-v1",
        "title": title,
        "subtitle": str(request.get("view_request") or request.get("question") or ""),
        "layout": _layout(request, profile),
        "composition": {
            "planning_role": "deterministic_fallback_draft",
            "target_block_count": max_count,
            "block_count_source": max_count_source,
            "visual_request": _dict(request.get("visual_request")),
            "llm_usage_note": "LLM should treat this as a safe draft only and prioritize raw question/view_request.",
        },
        "dataset_strategy": _dataset_strategy(payload, profile),
        "blocks": blocks,
        "warnings": _list(profile.get("warnings")),
    }
    plan = _apply_template_defaults(plan, catalog)
    result = _compact_report_payload(payload, profile)
    result["report_plan"] = plan
    # 03a 프롬프트 노드가 너무 큰 payload 전체를 보지 않아도 되도록 LLM용 요약을 따로 넣습니다.
    result["llm_context"] = _llm_context(profile, catalog)
    return result


def _apply_template_defaults(plan: dict[str, Any], catalog: dict[str, Any]) -> dict[str, Any]:
    """카탈로그 JSON에 들어온 기본 스타일/블록 기본값을 plan에 반영합니다."""

    defaults = _dict(catalog.get("template_defaults"))
    if not defaults:
        return plan
    result = deepcopy(plan)
    for key in ("audience", "report_goal", "layout"):
        value = defaults.get(key)
        if value and not result.get(key):
            result[key] = value
    for key in ("visual_style", "narrative"):
        value = _dict(defaults.get(key))
        if value:
            merged = _dict(result.get(key))
            merged.update(value)
            result[key] = merged
    block_defaults = _dict(defaults.get("block_defaults") or defaults.get("blocks"))
    if block_defaults:
        result["blocks"] = [_apply_block_default(block, block_defaults) for block in _list(result.get("blocks"))]
    return result


def _apply_block_default(block: Any, block_defaults: dict[str, Any]) -> Any:
    """특정 block_id에 대한 기본 설정을 하나의 block에 병합합니다."""

    if not isinstance(block, dict):
        return block
    block_id = str(block.get("block_id") or "")
    defaults = _dict(block_defaults.get(block_id))
    if not defaults:
        return block
    result = deepcopy(defaults)
    result.update(deepcopy(block))
    style = _dict(defaults.get("style"))
    style.update(_dict(block.get("style")))
    if style:
        result["style"] = style
    return result


def _prioritize_recommendations(recommendations: list[Any], preferred_ids: list[str]) -> list[dict[str, Any]]:
    """00번 표시 요구에서 직접 요청한 요소를 추천 목록 앞쪽으로 옮깁니다."""

    pinned_ids = {"report_header", "scope_summary"}
    by_id: dict[str, dict[str, Any]] = {}
    original_order: list[str] = []

    for item in recommendations:
        if not isinstance(item, dict):
            continue
        component_id = str(item.get("component_id") or "").strip()
        if not component_id:
            continue
        if component_id not in by_id:
            by_id[component_id] = item
            original_order.append(component_id)

    result: list[dict[str, Any]] = []

    def append_component(component_id: str) -> None:
        if not component_id or any(existing.get("component_id") == component_id for existing in result):
            return
        result.append(deepcopy(by_id.get(component_id) or {"component_id": component_id}))

    for component_id in original_order:
        if component_id in pinned_ids:
            append_component(component_id)
    for component_id in preferred_ids:
        if component_id not in pinned_ids:
            append_component(component_id)
    for component_id in original_order:
        append_component(component_id)
    return result


def _block_from_recommendation(block_id: str, recommendation: dict[str, Any], groups: dict[str, Any], shape: dict[str, Any]) -> dict[str, Any]:
    """추천 컴포넌트를 렌더러용 block 설정으로 변환합니다.

    예를 들어 `comparison_bar_chart` 추천은 x/y 컬럼, limit, chart_policy를 가진
    block dict로 바뀝니다. 필요한 컬럼이 부족하면 빈 dict를 반환해 건너뜁니다.
    """

    bindings = _dict(recommendation.get("suggested_bindings"))
    numeric = _strings(groups.get("numeric_columns"))
    dims = _strings(groups.get("dimension_columns"))
    times = _strings(groups.get("time_columns"))
    texts = _strings(groups.get("text_columns"))
    columns = _display_columns(groups, limit=12)

    if block_id == "report_header":
        return {"block_id": block_id, "title": "리포트 개요"}
    if block_id == "scope_summary":
        return {"block_id": block_id, "title": "데이터 범위"}
    if block_id == "warning_box":
        return {"block_id": block_id, "title": "확인 필요 사항"}
    if block_id == "empty_state":
        return {"block_id": block_id, "title": "조회 결과 없음"}
    if block_id == "kpi_card_grid":
        metrics = _list(bindings.get("metrics"))
        if not metrics:
            metrics = [{"label": column, "column": column, "aggregation": "sum"} for column in numeric[:4]]
        return {"block_id": block_id, "title": "주요 지표", "metrics": metrics[:4]}
    if block_id == "metric_delta_card_grid":
        metrics = _list(bindings.get("metrics")) or [{"label": column, "column": column, "aggregation": "avg"} for column in numeric[:4]]
        return {"block_id": block_id, "title": "증감 지표", "metrics": metrics[:4]}
    if block_id == "trend_line_chart" and times and numeric:
        return {"block_id": block_id, "title": "시간에 따른 변화", "x": str(bindings.get("x") or times[0]), "y": str(bindings.get("y") or numeric[0])}
    if block_id == "period_comparison_table":
        return {"block_id": block_id, "title": "기간별 상세 비교", "columns": _unique([*times[:1], *dims[:3], *numeric[:4], *texts[:2]])}
    if block_id == "comparison_bar_chart" and dims and numeric:
        return {
            "block_id": block_id,
            "title": "그룹별 비교",
            "x": str(bindings.get("x") or dims[0]),
            "y": str(bindings.get("y") or numeric[0]),
            "limit": _positive_int(bindings.get("limit"), 10),
            "chart_policy": {"orientation": "horizontal", "show_values": True, "limit": _positive_int(bindings.get("limit"), 10)},
        }
    if block_id == "donut_chart" and dims and numeric:
        return {
            "block_id": block_id,
            "title": "구성비",
            "x": str(bindings.get("x") or dims[0]),
            "y": str(bindings.get("y") or numeric[0]),
            "limit": _positive_int(bindings.get("limit"), 8),
            "width": "half",
            "chart_policy": {"show_percent": True, "show_legend": True, "limit": _positive_int(bindings.get("limit"), 8)},
        }
    if block_id == "grouped_bar_chart" and dims and len(numeric) >= 2:
        metrics = _list(bindings.get("metrics")) or [{"label": column, "column": column, "aggregation": "sum"} for column in numeric[:3]]
        return {
            "block_id": block_id,
            "title": "복수 지표 비교",
            "x": str(bindings.get("x") or dims[0]),
            "metrics": metrics[:3],
            "limit": _positive_int(bindings.get("limit"), 8),
            "width": "full",
            "chart_policy": {"show_values": True, "limit": _positive_int(bindings.get("limit"), 8)},
        }
    if block_id == "stacked_comparison_bar" and len(dims) >= 2 and numeric:
        return {
            "block_id": block_id,
            "title": "구성 비교",
            "x": str(bindings.get("x") or dims[0]),
            "series": str(bindings.get("series") or dims[1]),
            "y": str(bindings.get("y") or numeric[0]),
            "limit": _positive_int(bindings.get("limit"), 8),
            "chart_policy": {"show_legend": True, "limit": _positive_int(bindings.get("limit"), 8)},
        }
    if block_id == "ranking_table" and numeric:
        sort = _dict(bindings.get("sort")) or {"by": numeric[0], "direction": "desc"}
        return {
            "block_id": block_id,
            "title": "상위 항목",
            "columns": _strings(bindings.get("columns")) or _unique([*dims[:4], *numeric[:4], *texts[:2]]),
            "sort": sort,
            "limit": _positive_int(bindings.get("limit"), 10),
        }
    if block_id == "detail_data_table":
        return {"block_id": block_id, "title": "상세 데이터", "columns": _strings(bindings.get("columns")) or columns, "limit": _positive_int(bindings.get("limit"), 50)}
    if block_id == "pivot_matrix_table" and len(dims) >= 2 and numeric:
        return {"block_id": block_id, "title": "교차표", "x": str(bindings.get("x") or dims[0]), "series": str(bindings.get("series") or dims[1]), "y": str(bindings.get("y") or numeric[0])}
    if block_id == "heatmap_matrix" and len(dims) >= 2 and numeric:
        return {
            "block_id": block_id,
            "title": "교차 히트맵",
            "x": str(bindings.get("x") or dims[0]),
            "series": str(bindings.get("series") or dims[1]),
            "y": str(bindings.get("y") or numeric[0]),
            "limit": _positive_int(bindings.get("limit"), 8),
            "width": "full",
            "chart_policy": {"show_values": True, "limit": _positive_int(bindings.get("limit"), 8)},
        }
    if block_id == "distribution_histogram" and numeric:
        return {
            "block_id": block_id,
            "title": "분포",
            "x": str(bindings.get("x") or bindings.get("column") or numeric[0]),
            "width": "half",
            "chart_policy": {"bin_count": _positive_int(bindings.get("bin_count"), 8), "show_values": True},
        }
    if block_id == "scatter_plot" and len(numeric) >= 2:
        return {
            "block_id": block_id,
            "title": "상관/산포",
            "x": str(bindings.get("x") or numeric[0]),
            "y": str(bindings.get("y") or numeric[1]),
            "limit": _positive_int(bindings.get("limit"), 120),
            "width": "half",
        }
    if block_id == "outlier_exception_table":
        status_columns = _strings(groups.get("status_columns"))
        return {"block_id": block_id, "title": "이상/예외 항목", "columns": _unique([*status_columns, *dims[:4], *numeric[:4], *texts[:2]]) or columns, "limit": 50}
    if block_id == "insight_bullets":
        return {"block_id": block_id, "title": "핵심 해석"}
    if block_id == "recommendation_list":
        return {"block_id": block_id, "title": "다음 확인 사항"}
    if block_id == "method_note":
        return {"block_id": block_id, "title": "생성 기준"}
    return {}


def _resolve_max_blocks(max_blocks: Any, request: dict[str, Any], profile: dict[str, Any]) -> tuple[int, str]:
    """수동 블록 수 대신 00번의 표시 요구를 우선 사용해 블록 수 제한을 정합니다."""

    raw = str(max_blocks or "auto").strip().lower()
    if raw not in {"", "auto", "\uc790\ub3d9"}:
        return max(3, min(_positive_int(max_blocks, 8), 10)), "manual"

    visual_request = _dict(request.get("visual_request"))
    try:
        target = int(visual_request.get("target_block_count") or 0)
    except Exception:
        target = 0
    if target:
        return max(3, min(target, 10)), "visual_request"

    text = " ".join(
        str(item or "")
        for item in (
            request.get("question"),
            request.get("view_request"),
            profile.get("intent_text"),
        )
    ).lower()
    if _contains(text, ["\uac04\ub2e8", "\uc9e7\uac8c", "simple", "brief"]):
        return 5, "auto_simple"
    if _contains(text, ["\uc0c1\uc138", "\ud48d\ubd80", "detailed", "full"]):
        return 10, "auto_detailed"
    return 8, "auto_default"


def _title(request: dict[str, Any], profile: dict[str, Any]) -> str:
    """질문 문장을 바탕으로 기본 리포트 제목을 만듭니다."""

    question = str(request.get("question") or profile.get("question") or "").strip()
    if "리포트" in question or "보고서" in question:
        return question[:80]
    if question:
        return f"{question[:60]} 리포트"
    return "HTML 데이터 리포트"


def _layout(request: dict[str, Any], profile: dict[str, Any]) -> str:
    """질문 힌트를 바탕으로 기본 레이아웃 유형을 고릅니다."""

    hints = _dict(profile.get("question_hints"))
    if hints.get("detail"):
        return "query_review"
    if hints.get("exception"):
        return "diagnosis"
    if hints.get("summary") or hints.get("comparison") or hints.get("trend"):
        return "dashboard"
    return "report"


def _display_columns(groups: dict[str, Any], limit: int) -> list[str]:
    """표나 LLM 컨텍스트에 보여줄 대표 컬럼을 고릅니다."""

    return _unique(
        [
            *_strings(groups.get("time_columns")),
            *_strings(groups.get("dimension_columns")),
            *_strings(groups.get("numeric_columns")),
            *_strings(groups.get("status_columns")),
            *_strings(groups.get("text_columns")),
        ]
    )[:limit]


def _compact_report_payload(payload: dict[str, Any], profile: dict[str, Any]) -> dict[str, Any]:
    """뒤 노드에 필요한 최소 payload만 남깁니다.

    앞 노드의 중복 정보를 모두 넘기면 Langflow 연결도 복잡하고 LLM 입력도 커지므로,
    요청/데이터/API 응답/요약 정도만 정리해 전달합니다.
    """

    shape = _dict(profile.get("shape"))
    groups = _dict(profile.get("column_groups"))
    api = _dict(payload.get("api_response"))
    data = _dict(api.get("data")) or _dict(payload.get("data"))
    result: dict[str, Any] = {
        "payload_version": payload.get("payload_version", "html-report-demo-v1"),
        "flow_type": payload.get("flow_type", "html_report_demo"),
        "status": payload.get("status", "ok"),
        "request": _dict(payload.get("request")),
        "available_datasets": _list(payload.get("available_datasets")),
        "available_data_views": _list(payload.get("available_data_views")),
        "data_views": _list(payload.get("data_views")),
        "relationship_candidates": _list(payload.get("relationship_candidates")),
        "api_response": {
            "status": api.get("status", payload.get("status", "ok")),
            "response_type": api.get("response_type", "demo_data"),
            "message": api.get("message", ""),
            "data": data,
        },
        "data_summary": {
            "row_count": shape.get("row_count", data.get("row_count", 0)),
            "preview_row_count": shape.get("preview_row_count", len(_list(data.get("rows")))),
            "column_count": shape.get("column_count", len(_list(data.get("columns")))),
            "data_is_preview": bool(shape.get("data_is_preview") or data.get("data_is_preview")),
            "numeric_columns": _strings(groups.get("numeric_columns")),
            "dimension_columns": _strings(groups.get("dimension_columns")),
            "time_columns": _strings(groups.get("time_columns")),
            "status_columns": _strings(groups.get("status_columns")),
            "active_data_view_id": shape.get("active_data_view_id") or data.get("data_view_id") or "",
            "active_data_view_strategy": shape.get("active_data_view_strategy") or data.get("strategy") or "",
        },
        "warnings": _list(payload.get("warnings")) or _list(profile.get("warnings")),
        "errors": _list(payload.get("errors")) or _list(profile.get("errors")),
    }
    return result


def _llm_context(profile: dict[str, Any], catalog: dict[str, Any]) -> dict[str, Any]:
    """LLM 프롬프트에 넣기 좋은 크기로 데이터 프로파일과 카탈로그를 요약합니다."""

    return {
        "data_profile": _compact_profile_for_llm(profile),
        "html_component_catalog": _compact_catalog_for_llm(catalog),
    }


def _compact_profile_for_llm(profile: dict[str, Any]) -> dict[str, Any]:
    """데이터 프로파일 중 LLM 계획 수립에 필요한 항목만 추립니다."""

    return {
        "question": profile.get("question") or "",
        "shape": _dict(profile.get("shape")),
        "column_groups": _dict(profile.get("column_groups")),
        "columns": [
            {
                "name": item.get("name"),
                "inferred_type": item.get("inferred_type"),
                "semantic_hint": item.get("semantic_hint", ""),
                "sample_values": _list(item.get("sample_values"))[:3],
            }
            for item in _list(profile.get("columns"))
            if isinstance(item, dict)
        ],
        "question_hints": _dict(profile.get("question_hints")),
        "report_signals": _dict(profile.get("report_signals")),
        "available_datasets": _list(profile.get("available_datasets")),
        "available_data_views": _list(profile.get("available_data_views")),
        "relationship_candidates": _list(profile.get("relationship_candidates")),
        "data_view_profiles": _list(profile.get("data_view_profiles")),
        "warnings": _list(profile.get("warnings")),
        "errors": _list(profile.get("errors")),
    }


def _dataset_strategy(payload: dict[str, Any], profile: dict[str, Any]) -> dict[str, Any]:
    """현재 active data view가 어떤 방식으로 만들어졌는지 plan에 기록합니다."""

    data = _dict(_dict(payload.get("api_response")).get("data"))
    shape = _dict(profile.get("shape"))
    active_view_id = str(data.get("data_view_id") or shape.get("active_data_view_id") or "")
    strategy = str(data.get("strategy") or shape.get("active_data_view_strategy") or "select")
    return {
        "mode": strategy,
        "active_data_view_id": active_view_id,
        "source_dataset_ids": _strings(data.get("source_dataset_ids")),
        "join_keys": _strings(data.get("join_keys")),
        "relationship_candidates": _list(payload.get("relationship_candidates"))[:6],
    }


def _compact_catalog_for_llm(catalog: dict[str, Any]) -> dict[str, Any]:
    """컴포넌트 카탈로그 중 LLM이 선택/배치에 참고할 정보만 추립니다."""

    return {
        "components": [
            _compact_dict(
                {
                    "component_id": item.get("component_id"),
                    "display_name": item.get("display_name"),
                    "description": item.get("description"),
                    "layout_role": item.get("layout_role"),
                    "data_contract": _dict(item.get("data_contract")),
                    "template_guidance": item.get("template_guidance") or item.get("usage_guidance"),
                    "style_defaults": _dict(item.get("style_defaults")),
                    "default_spec": _dict(item.get("default_spec")),
                    "example_spec": _dict(item.get("example_spec")),
                }
            )
            for item in _list(catalog.get("components"))
            if isinstance(item, dict)
        ],
        "recommended_components": _list(catalog.get("recommended_components")),
        "template_defaults": _dict(catalog.get("template_defaults")),
        "style_presets": deepcopy(catalog.get("style_presets")) if isinstance(catalog.get("style_presets"), (dict, list)) else {},
        "report_presets": deepcopy(catalog.get("report_presets")) if isinstance(catalog.get("report_presets"), (dict, list)) else {},
        "catalog_notes": _list(catalog.get("catalog_notes")),
    }


def _compact_dict(value: dict[str, Any]) -> dict[str, Any]:
    """빈 문자열/빈 dict/빈 list/None 값을 제거해 JSON을 작게 만듭니다."""

    return {key: item for key, item in value.items() if item not in ("", {}, [], None)}


def _payload(value: Any) -> dict[str, Any]:
    """Langflow Data/Message/dict/JSON 문자열을 일반 dict로 맞춥니다."""

    if isinstance(value, dict):
        return deepcopy(value)
    data = getattr(value, "data", None)
    if isinstance(data, dict):
        return deepcopy(data)
    text = getattr(value, "text", None) or getattr(value, "content", None)
    if isinstance(text, str) and text.strip():
        try:
            parsed = json.loads(text)
        except Exception:
            return {"text": text}
        return deepcopy(parsed) if isinstance(parsed, dict) else {"text": text}
    return {}


def _dict(value: Any) -> dict[str, Any]:
    """dict면 복사본을, 아니면 빈 dict를 반환합니다."""

    return deepcopy(value) if isinstance(value, dict) else {}


def _list(value: Any) -> list[Any]:
    """list면 복사본을, 아니면 빈 list를 반환합니다."""

    return deepcopy(value) if isinstance(value, list) else []


def _strings(value: Any) -> list[str]:
    """문자열 목록을 정리하고 중복을 제거합니다."""

    if not isinstance(value, list):
        return []
    result = []
    for item in value:
        text = str(item or "").strip()
        if text and text not in result:
            result.append(text)
    return result


def _unique(values: list[Any]) -> list[str]:
    """값을 문자열로 바꾼 뒤 빈 값과 중복을 제거합니다."""

    result = []
    for value in values:
        text = str(value or "").strip()
        if text and text not in result:
            result.append(text)
    return result


def _positive_int(value: Any, default: int) -> int:
    """값을 양의 정수로 바꾸고 실패하면 default를 사용합니다."""

    try:
        parsed = int(value)
    except Exception:
        parsed = default
    return max(1, parsed)


class AutoHtmlPlanBuilder(Component):
    """Langflow 화면에 표시되는 03번 커스텀 컴포넌트 클래스."""

    display_name = "03 기본 리포트 계획"
    description = "요소 추천 결과를 바탕으로 LLM이 보완할 수 있는 기본 리포트 계획을 만듭니다."
    icon = "ListChecks"
    inputs = [
        DataInput(name="payload", display_name="요청 데이터", required=True),
        DataInput(name="data_profile", display_name="데이터 분석 결과", required=True),
        DataInput(name="html_component_catalog", display_name="요소 추천 결과", required=True),
        MessageTextInput(name="max_blocks", display_name="블록 수 제한", value="auto", advanced=True),
    ]
    outputs = [Output(name="payload_out", display_name="기본 계획", method="build_payload")]

    def build_payload(self) -> Data:
        """요소 추천 결과를 받아 기본 계획 payload를 출력합니다."""

        result = build_auto_html_plan(
            getattr(self, "payload", None),
            getattr(self, "data_profile", None),
            getattr(self, "html_component_catalog", None),
            getattr(self, "max_blocks", "auto"),
        )
        plan = result.get("report_plan", {})
        self.status = {"blocks": [block.get("block_id") for block in plan.get("blocks", [])], "layout": plan.get("layout")}
        return Data(data=result)

from __future__ import annotations

"""03b LLM 계획 검증 노드.

이 파일은 LLM이 만든 report_plan JSON을 그대로 사용하지 않고,
허용된 block_id인지, 실제 컬럼명만 참조하는지, width/style 값이 안전한지 검증합니다.
검증에 실패하면 03번 기본 계획으로 fallback해서 flow가 중단되지 않게 합니다.
"""

import json
import re
from copy import deepcopy
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, MessageTextInput, Output
from lfx.schema.data import Data


# LLM이 마음대로 CSS/HTML을 만들지 못하도록, 사용할 수 있는 값들을 작은 set으로 제한합니다.
WIDTHS = {"full", "two_third", "half", "third"}
EMPHASIS = {"high", "medium", "low", "critical"}
DENSITIES = {"compact", "comfortable"}
FONT_SCALES = {"small", "normal", "large"}
LAYOUTS = {"dashboard", "query_review", "diagnosis", "executive_summary", "detail_review", "report"}
AGGREGATIONS = {"sum", "avg", "average", "mean", "min", "max", "count", "nunique"}
AUDIENCES = {"operator", "analyst", "executive", "engineer", "general"}
REPORT_GOALS = {"monitor", "compare", "diagnose", "explain", "audit", "explore"}
TONES = {"info", "positive", "warning", "danger", "neutral"}
OPERATORS = {"eq", "ne", "gt", "gte", "lt", "lte", "contains", "in", "not_in"}
CHART_TYPES = {"bar", "horizontal_bar", "grouped_bar", "stacked_bar", "line", "donut", "histogram", "scatter", "heatmap"}
ORIENTATIONS = {"horizontal", "vertical"}


def normalize_llm_html_plan(base_payload_value: Any, llm_response_value: Any, component_catalog_value: Any = None) -> dict[str, Any]:
    """LLM 응답에서 JSON 계획을 추출하고 최종 report_plan으로 정규화합니다."""

    payload = _payload(base_payload_value)
    llm_text = _text(llm_response_value)
    llm_json = _extract_json_object(llm_text)
    base_plan = _dict(payload.get("report_plan"))
    llm_context = _dict(payload.get("llm_context"))
    catalog = _payload(component_catalog_value) or _dict(payload.get("html_component_catalog")) or _dict(llm_context.get("html_component_catalog"))
    allowed_blocks = _allowed_blocks(catalog)
    columns = _available_columns(payload)
    data_view_ids = _available_data_view_ids(payload)
    warnings = _list(payload.get("warnings"))

    if not llm_json:
        # LLM이 JSON이 아닌 설명문만 반환해도 리포트 생성은 계속되도록 기본 계획을 사용합니다.
        result = deepcopy(payload)
        result["report_plan"] = _mark_plan(base_plan, "deterministic_fallback", ["LLM response did not contain a JSON object."])
        result["llm_report_plan"] = {"status": "fallback", "llm_text_preview": llm_text[:1200], "errors": ["missing_json"]}
        result["warnings"] = warnings + ["LLM plan fallback: JSON object not found."]
        return result

    normalized_plan, plan_warnings = _normalize_plan(llm_json, base_plan, allowed_blocks, columns, data_view_ids)
    result = deepcopy(payload)
    result["report_plan"] = normalized_plan
    result["llm_report_plan"] = {
        "status": "ok" if normalized_plan.get("plan_source") == "llm" else "fallback",
        "raw_plan": llm_json,
        "request_interpretation": _dict(normalized_plan.get("request_interpretation")),
        "warnings": plan_warnings,
        "llm_text_preview": llm_text[:1200],
    }
    result["warnings"] = warnings + [f"LLM plan warning: {item}" for item in plan_warnings]
    return result


def _normalize_plan(
    llm_json: dict[str, Any],
    base_plan: dict[str, Any],
    allowed_blocks: set[str],
    columns: set[str],
    data_view_ids: set[str],
) -> tuple[dict[str, Any], list[str]]:
    """Validate the LLM output while preserving the user's interpreted intent."""

    warnings: list[str] = []
    # The preferred output is one object with request_interpretation and plan fields,
    # but this also accepts {"request_interpretation": ..., "report_plan": {...}}.
    llm_plan = _dict(llm_json.get("report_plan")) or llm_json
    interpretation_raw = _dict(llm_json.get("request_interpretation")) or _dict(llm_plan.get("request_interpretation"))
    request_interpretation = _normalize_request_interpretation(interpretation_raw)

    base_blocks = [item for item in _list(base_plan.get("blocks")) if isinstance(item, dict)]
    base_by_id = {str(item.get("block_id")): item for item in base_blocks}
    raw_blocks = [item for item in _list(llm_plan.get("blocks")) if isinstance(item, dict)]
    blocks: list[dict[str, Any]] = []

    for raw in raw_blocks:
        block_id = str(raw.get("block_id") or "").strip()
        if block_id not in allowed_blocks:
            # Unknown block IDs are skipped, but valid LLM blocks still survive.
            warnings.append(f"Skipped unknown block_id: {block_id or '(blank)'}")
            continue
        base = _dict(base_by_id.get(block_id))
        block = _normalize_block(raw, base, columns, data_view_ids, warnings)
        if block and not any(existing.get("block_id") == block_id for existing in blocks):
            blocks.append(block)

    if not blocks:
        warnings.append("No valid LLM blocks remained after validation; deterministic base blocks were used.")
        fallback = _mark_plan(base_plan, "deterministic_fallback", warnings)
        if request_interpretation:
            fallback["request_interpretation"] = request_interpretation
        return fallback, warnings

    if not any(block.get("block_id") == "report_header" for block in blocks) and "report_header" in allowed_blocks:
        blocks.insert(0, _normalize_block({"block_id": "report_header", "width": "full", "emphasis": "high"}, _dict(base_by_id.get("report_header")), columns, data_view_ids, warnings))

    plan = deepcopy(base_plan)
    plan["plan_version"] = "html-report-plan-llm-v1"
    plan["plan_source"] = "llm"
    plan["title"] = _short_text(llm_plan.get("title"), base_plan.get("title") or "HTML 데이터 리포트", 90)
    plan["subtitle"] = _short_text(llm_plan.get("subtitle"), base_plan.get("subtitle") or "", 160)
    plan["filename_hint"] = _short_text(llm_plan.get("filename_hint"), base_plan.get("filename_hint") or plan["title"], 80)
    plan["audience"] = _choice(llm_plan.get("audience"), AUDIENCES, base_plan.get("audience") or "general")
    plan["report_goal"] = _choice(llm_plan.get("report_goal"), REPORT_GOALS, base_plan.get("report_goal") or "explore")
    plan["layout"] = _choice(llm_plan.get("layout"), LAYOUTS, base_plan.get("layout") or "dashboard")
    plan["visual_style"] = _normalize_visual_style(_dict(llm_plan.get("visual_style")), _dict(base_plan.get("visual_style")))
    plan["narrative"] = _normalize_narrative(_dict(llm_plan.get("narrative")), _dict(base_plan.get("narrative")))
    plan["dataset_strategy"] = _normalize_dataset_strategy(_dict(llm_plan.get("dataset_strategy")), _dict(base_plan.get("dataset_strategy")), data_view_ids, warnings)
    if request_interpretation:
        plan["request_interpretation"] = request_interpretation
    reading_order = _normalize_string_list(llm_plan.get("reading_order"), 8, 40)
    if reading_order:
        plan["reading_order"] = reading_order
    plan["blocks"] = blocks[:10]
    plan["warnings"] = _list(base_plan.get("warnings"))
    notes = _list(llm_plan.get("reasoning_notes")) or _list(llm_json.get("reasoning_notes"))
    plan["llm_reasoning_notes"] = [str(item)[:200] for item in notes[:6]]
    return plan, warnings


def _normalize_block(raw: dict[str, Any], base: dict[str, Any], columns: set[str], data_view_ids: set[str], warnings: list[str]) -> dict[str, Any]:
    """LLM이 만든 block 하나를 렌더러가 안전하게 쓸 수 있는 형태로 정리합니다.

    컬럼명은 실제 데이터 컬럼에 있는 경우만 허용하고,
    width/emphasis/density 같은 레이아웃 값도 미리 정한 후보 안에서만 통과시킵니다.
    """

    block_id = str(raw.get("block_id") or base.get("block_id") or "").strip()
    block = deepcopy(base)
    block["block_id"] = block_id
    block["title"] = _short_text(raw.get("title"), base.get("title") or block_id.replace("_", " ").title(), 80)
    block["width"] = _choice(raw.get("width"), WIDTHS, base.get("width") or _default_width(block_id))
    block["emphasis"] = _choice(raw.get("emphasis"), EMPHASIS, base.get("emphasis") or "medium")
    block["density"] = _choice(raw.get("density"), DENSITIES, base.get("density") or "comfortable")
    block["font_scale"] = _choice(raw.get("font_scale"), FONT_SCALES, base.get("font_scale") or "normal")
    data_view_id = str(raw.get("data_view_id") or base.get("data_view_id") or "").strip()
    if data_view_id:
        if data_view_id in data_view_ids:
            block["data_view_id"] = data_view_id
        else:
            warnings.append(f"Ignored invalid data_view_id for {block_id}: {data_view_id}")
    for key, limit in (
        ("section", 48),
        ("description", 180),
        ("insight", 220),
        ("badge", 32),
        ("footnote", 180),
    ):
        value = str(raw.get(key) or "").strip()
        if value:
            block[key] = value[:limit]

    lines = _normalize_string_list(raw.get("lines") or raw.get("bullets"), 8, 180)
    if lines:
        block["lines"] = lines
    items = _normalize_string_list(raw.get("items"), 8, 180)
    if items:
        block["items"] = items

    style = _dict(base.get("style"))
    raw_style = _dict(raw.get("style"))
    accent = _safe_color(raw_style.get("accent_color") or raw.get("accent_color"))
    if accent:
        style["accent_color"] = accent
    if style:
        block["style"] = style

    for key in ("x", "y", "series"):
        value = str(raw.get(key) or "").strip()
        if value and value in columns:
            block[key] = value
        elif value:
            # LLM이 존재하지 않는 컬럼명을 만들면 무시하고 warning만 남깁니다.
            warnings.append(f"Ignored invalid column for {block_id}.{key}: {value}")

    raw_columns = _valid_columns(_list(raw.get("columns")), columns)
    if raw_columns:
        block["columns"] = raw_columns[:14]
    elif "columns" in raw and raw.get("columns"):
        warnings.append(f"Ignored invalid columns for {block_id}.columns")

    raw_metrics = _normalize_metrics(_list(raw.get("metrics")), columns, warnings, block_id)
    if raw_metrics:
        block["metrics"] = raw_metrics[:4]

    raw_sort = _dict(raw.get("sort"))
    sort_by = str(raw_sort.get("by") or "").strip()
    if sort_by in columns:
        block["sort"] = {"by": sort_by, "direction": _choice(raw_sort.get("direction"), {"asc", "desc"}, "desc")}

    if raw.get("limit") is not None:
        block["limit"] = min(max(_positive_int(raw.get("limit"), _positive_int(base.get("limit"), 10)), 1), 200)

    chart_policy = _normalize_chart_policy(_dict(raw.get("chart_policy")), columns, warnings, block_id)
    if chart_policy:
        block["chart_policy"] = chart_policy
        for key in (
            "x",
            "y",
            "series",
            "limit",
            "show_values",
            "show_legend",
            "show_percent",
            "normalize",
            "bin_count",
            "orientation",
            "chart_type",
        ):
            if key in chart_policy:
                block[key] = chart_policy[key]
        if chart_policy.get("metrics"):
            block["metrics"] = chart_policy["metrics"]

    table_policy = _normalize_table_policy(_dict(raw.get("table_policy")), columns, warnings, block_id)
    if table_policy:
        block["table_policy"] = table_policy
        if table_policy.get("columns"):
            block["columns"] = table_policy["columns"]
        if table_policy.get("sort"):
            block["sort"] = table_policy["sort"]
        if table_policy.get("limit") is not None:
            block["limit"] = table_policy["limit"]
        if table_policy.get("show_row_numbers") is not None:
            block["show_row_numbers"] = table_policy["show_row_numbers"]

    raw_filter_rules = raw.get("filter_rules")
    if raw_filter_rules is None:
        raw_filter_rules = _dict(raw.get("table_policy")).get("filter_rules")
    filter_rules = _normalize_filter_rules(_list(raw_filter_rules), columns, warnings, block_id)
    if filter_rules:
        block["filter_rules"] = filter_rules[:10]
        block["filter_logic"] = _choice(raw.get("filter_logic") or _dict(raw.get("table_policy")).get("filter_logic"), {"and", "or"}, "and")

    annotations = _normalize_annotations(_list(raw.get("annotations")))
    if annotations:
        block["annotations"] = annotations[:6]

    highlight_rules = _normalize_highlight_rules(_list(raw.get("highlight_rules")), columns, warnings, block_id)
    if highlight_rules:
        block["highlight_rules"] = highlight_rules[:8]

    return block


def _normalize_narrative(raw: dict[str, Any], base: dict[str, Any]) -> dict[str, Any]:
    """LLM이 작성한 요약/해석/주의사항 문장을 길이 제한 안에서 정리합니다."""

    result = deepcopy(base)
    summary = str(raw.get("executive_summary") or raw.get("summary") or "").strip()
    if summary:
        result["executive_summary"] = summary[:320]
    for key in ("key_findings", "caveats", "recommendations", "data_quality_notes"):
        values = _normalize_string_list(raw.get(key), 8, 220)
        if values:
            result[key] = values
    return result


def _normalize_request_interpretation(raw: dict[str, Any]) -> dict[str, Any]:
    """Keep the LLM's request understanding in a compact, renderer-safe form."""

    if not raw:
        return {}
    result: dict[str, Any] = {}
    for key, limit in (
        ("user_goal", 240),
        ("data_focus", 200),
        ("layout_intent", 240),
        ("style_intent", 200),
    ):
        value = str(raw.get(key) or "").strip()
        if value:
            result[key] = value[:limit]
    for key in ("requested_visuals", "requested_blocks", "requested_order", "requested_columns", "data_binding_plan"):
        values = _normalize_string_list(raw.get(key), 12, 80)
        if values:
            result[key] = values
    value_conditions = []
    for item in _list(raw.get("requested_value_conditions")):
        if isinstance(item, dict):
            column = str(item.get("column") or "").strip()
            operator = str(item.get("operator") or "").strip()
            value = item.get("value")
            purpose = str(item.get("purpose") or "").strip()
            compact = {key: val for key, val in {"column": column, "operator": operator, "value": value, "purpose": purpose}.items() if val not in ("", None, [], {})}
            if compact:
                value_conditions.append(compact)
        else:
            text = str(item or "").strip()
            if text:
                value_conditions.append({"text": text[:160]})
        if len(value_conditions) >= 12:
            break
    if value_conditions:
        result["requested_value_conditions"] = value_conditions
    unmet = []
    for item in _list(raw.get("unmet_requests")):
        if isinstance(item, dict):
            request = str(item.get("request") or item.get("item") or item.get("label") or "").strip()
            reason = str(item.get("reason") or item.get("why") or item.get("value") or "").strip()
            text = ": ".join(part for part in (request, reason) if part)
        else:
            text = str(item or "").strip()
        if text and text not in unmet:
            unmet.append(text[:220])
        if len(unmet) >= 8:
            break
    if unmet:
        result["unmet_requests"] = unmet
    try:
        target = int(raw.get("target_block_count") or 0)
    except Exception:
        target = 0
    if target:
        result["target_block_count"] = max(1, min(target, 12))
    return result


def _normalize_visual_style(raw: dict[str, Any], base: dict[str, Any]) -> dict[str, Any]:
    """density, font_scale, 색상 같은 전체 스타일 설정을 검증합니다."""

    result = deepcopy(base)
    result["density"] = _choice(raw.get("density"), DENSITIES, base.get("density") or "comfortable")
    result["font_scale"] = _choice(raw.get("font_scale"), FONT_SCALES, base.get("font_scale") or "normal")
    result["max_width"] = _choice(raw.get("max_width"), {"normal", "wide"}, base.get("max_width") or "normal")
    accent = _safe_color(raw.get("accent_color") or base.get("accent_color"))
    secondary = _safe_color(raw.get("secondary_color") or base.get("secondary_color"))
    if accent:
        result["accent_color"] = accent
    if secondary:
        result["secondary_color"] = secondary
    return result


def _normalize_dataset_strategy(raw: dict[str, Any], base: dict[str, Any], data_view_ids: set[str], warnings: list[str]) -> dict[str, Any]:
    """LLM이 적은 dataset/data view 사용 계획을 안전하게 보존합니다."""

    result = deepcopy(base)
    active = str(raw.get("active_data_view_id") or raw.get("data_view_id") or base.get("active_data_view_id") or "").strip()
    if active:
        if active in data_view_ids:
            result["active_data_view_id"] = active
        else:
            warnings.append(f"Ignored invalid dataset_strategy active_data_view_id: {active}")
    mode = str(raw.get("mode") or raw.get("strategy") or base.get("mode") or "").strip().lower()
    if mode in {"select", "join", "union", "separate_sections"}:
        result["mode"] = mode
    for key in ("source_dataset_ids", "join_keys"):
        values = _normalize_string_list(raw.get(key), 12, 80)
        if values:
            result[key] = values
    return result


def _normalize_chart_policy(policy: dict[str, Any], columns: set[str], warnings: list[str], block_id: str) -> dict[str, Any]:
    """차트 설정을 검증합니다.

    chart_type, orientation, x/y/series, limit 같은 값만 통과시키고,
    컬럼명이 실제 데이터에 없으면 해당 값은 버립니다.
    """

    result: dict[str, Any] = {}
    for key in ("x", "y", "series"):
        value = str(policy.get(key) or "").strip()
        if value and value in columns:
            result[key] = value
        elif value:
            warnings.append(f"Ignored invalid chart_policy column for {block_id}.{key}: {value}")
    if policy.get("limit") is not None:
        result["limit"] = min(max(_positive_int(policy.get("limit"), 10), 1), 100)
    if policy.get("bin_count") is not None:
        result["bin_count"] = min(max(_positive_int(policy.get("bin_count"), 8), 3), 20)
    chart_type = _choice(policy.get("chart_type"), CHART_TYPES, "")
    if chart_type:
        result["chart_type"] = chart_type
    orientation = _choice(policy.get("orientation"), ORIENTATIONS, "")
    if orientation:
        result["orientation"] = orientation
    if policy.get("show_values") is not None:
        result["show_values"] = _bool(policy.get("show_values"))
    if policy.get("show_legend") is not None:
        result["show_legend"] = _bool(policy.get("show_legend"))
    if policy.get("show_percent") is not None:
        result["show_percent"] = _bool(policy.get("show_percent"))
    if policy.get("normalize") is not None:
        result["normalize"] = _bool(policy.get("normalize"))
    metrics = _normalize_metrics(_list(policy.get("metrics")), columns, warnings, block_id)
    if metrics:
        result["metrics"] = metrics[:4]
    return result


def _normalize_table_policy(policy: dict[str, Any], columns: set[str], warnings: list[str], block_id: str) -> dict[str, Any]:
    """표 설정을 검증합니다. 컬럼 목록, 정렬 컬럼, row 수 제한을 안전한 값으로 보정합니다."""

    result: dict[str, Any] = {}
    valid_columns = _valid_columns(_list(policy.get("columns")), columns)
    if valid_columns:
        result["columns"] = valid_columns[:14]
    elif policy.get("columns"):
        warnings.append(f"Ignored invalid table_policy columns for {block_id}")
    sort_by = str(policy.get("sort_by") or _dict(policy.get("sort")).get("by") or "").strip()
    if sort_by:
        if sort_by in columns:
            result["sort"] = {
                "by": sort_by,
                "direction": _choice(policy.get("sort_direction") or _dict(policy.get("sort")).get("direction"), {"asc", "desc"}, "desc"),
            }
        else:
            warnings.append(f"Ignored invalid table_policy sort column for {block_id}: {sort_by}")
    if policy.get("limit") is not None:
        result["limit"] = min(max(_positive_int(policy.get("limit"), 50), 1), 200)
    if policy.get("show_row_numbers") is not None:
        result["show_row_numbers"] = _bool(policy.get("show_row_numbers"))
    return result


def _normalize_annotations(values: list[Any]) -> list[dict[str, str]]:
    """차트/카드에 표시할 짧은 주석 chip 목록을 정리합니다."""

    result = []
    for item in values:
        if isinstance(item, dict):
            label = _short_text(item.get("label"), "", 42)
            value = _short_text(item.get("value") or item.get("text"), "", 90)
            tone = _choice(item.get("tone"), TONES, "info")
        else:
            label = ""
            value = _short_text(item, "", 90)
            tone = "info"
        if label or value:
            result.append({"label": label, "value": value, "tone": tone})
    return result


def _normalize_highlight_rules(values: list[Any], columns: set[str], warnings: list[str], block_id: str) -> list[dict[str, Any]]:
    """테이블 row 강조 규칙을 검증합니다."""

    result = []
    for item in values:
        if not isinstance(item, dict):
            continue
        column = str(item.get("column") or "").strip()
        if column not in columns:
            warnings.append(f"Ignored invalid highlight column for {block_id}: {column}")
            continue
        result.append(
            {
                "column": column,
                "operator": _choice(item.get("operator"), OPERATORS, "eq"),
                "value": _normalize_rule_value(item.get("value")),
                "tone": _choice(item.get("tone"), TONES, "warning"),
            }
        )
    return result


def _normalize_filter_rules(values: list[Any], columns: set[str], warnings: list[str], block_id: str) -> list[dict[str, Any]]:
    """차트/표에 적용할 row 필터 규칙을 검증합니다."""

    result = []
    for item in values:
        if not isinstance(item, dict):
            continue
        column = str(item.get("column") or "").strip()
        if column not in columns:
            warnings.append(f"Ignored invalid filter column for {block_id}: {column}")
            continue
        result.append(
            {
                "column": column,
                "operator": _choice(item.get("operator"), OPERATORS, "eq"),
                "value": _normalize_rule_value(item.get("value")),
            }
        )
    return result


def _normalize_rule_value(value: Any) -> Any:
    """filter/highlight 비교값을 JSON으로 안전하게 보존합니다."""

    if isinstance(value, list):
        result = []
        for item in value[:20]:
            if isinstance(item, (str, int, float, bool)) or item is None:
                result.append(item)
            else:
                result.append(str(item))
        return result
    if isinstance(value, (str, int, float, bool)) or value is None:
        return value
    return str(value)


def _mark_plan(plan: dict[str, Any], source: str, warnings: list[str]) -> dict[str, Any]:
    """plan에 출처와 경고 메모를 붙입니다."""

    result = deepcopy(plan)
    result["plan_source"] = source
    result["llm_reasoning_notes"] = warnings[:6]
    return result


def _allowed_blocks(catalog: dict[str, Any]) -> set[str]:
    """카탈로그에서 허용된 block_id 목록을 가져옵니다."""

    result = {str(item.get("component_id")) for item in _list(catalog.get("components")) if isinstance(item, dict) and item.get("component_id")}
    return result or {
        "report_header",
        "scope_summary",
        "warning_box",
        "empty_state",
        "kpi_card_grid",
        "trend_line_chart",
        "comparison_bar_chart",
        "ranking_table",
        "detail_data_table",
        "insight_bullets",
        "method_note",
    }


def _available_columns(payload: dict[str, Any]) -> set[str]:
    """데이터 프로파일과 실제 row에서 사용할 수 있는 컬럼명을 모읍니다."""

    llm_context = _dict(payload.get("llm_context"))
    profile = _dict(payload.get("data_profile")) or _dict(llm_context.get("data_profile"))
    data = _dict(_dict(payload.get("api_response")).get("data"))
    result = {str(item.get("name")) for item in _list(profile.get("columns")) if isinstance(item, dict) and item.get("name")}
    result.update(str(item) for item in _list(data.get("columns")) if item)
    for view in _list(payload.get("data_views")):
        if isinstance(view, dict):
            result.update(str(item) for item in _list(view.get("columns")) if item)
            for row in _rows(view.get("rows"))[:20]:
                result.update(str(key) for key in row.keys())
    for view_profile in _list(profile.get("data_view_profiles")):
        if isinstance(view_profile, dict):
            for column in _list(view_profile.get("columns")):
                if isinstance(column, dict) and column.get("name"):
                    result.add(str(column.get("name")))
    for row in _rows(data.get("rows")):
        result.update(str(key) for key in row.keys())
    return result


def _available_data_view_ids(payload: dict[str, Any]) -> set[str]:
    """payload 안에서 block.data_view_id로 지정 가능한 view id를 모읍니다."""

    result = set()
    request = _dict(payload.get("request"))
    if request.get("active_data_view_id"):
        result.add(str(request.get("active_data_view_id")))
    data = _dict(_dict(payload.get("api_response")).get("data"))
    if data.get("data_view_id"):
        result.add(str(data.get("data_view_id")))
    for view in _list(payload.get("data_views")) + _list(payload.get("available_data_views")):
        if isinstance(view, dict) and view.get("data_view_id"):
            result.add(str(view.get("data_view_id")))
    return result


def _normalize_metrics(metrics: list[Any], columns: set[str], warnings: list[str], block_id: str) -> list[dict[str, Any]]:
    """KPI/차트 metric 설정을 검증합니다."""

    result = []
    for item in metrics:
        if not isinstance(item, dict):
            continue
        column = str(item.get("column") or "").strip()
        if column not in columns:
            warnings.append(f"Ignored invalid metric column for {block_id}: {column}")
            continue
        result.append(
            {
                "label": _short_text(item.get("label"), column, 32),
                "column": column,
                "aggregation": _choice(item.get("aggregation"), AGGREGATIONS, "sum"),
            }
        )
    return result


def _valid_columns(values: list[Any], columns: set[str]) -> list[str]:
    """후보 컬럼 목록에서 실제 존재하는 컬럼만 남깁니다."""

    result = []
    for value in values:
        text = str(value or "").strip()
        if text and text in columns and text not in result:
            result.append(text)
    return result


def _normalize_string_list(value: Any, limit: int, item_limit: int) -> list[str]:
    """문자열 또는 문자열 목록을 개수/길이 제한에 맞게 정리합니다."""

    result = []
    values = _list(value)
    if isinstance(value, str):
        values = [value]
    for item in values:
        if isinstance(item, dict):
            text = str(item.get("text") or item.get("label") or item.get("value") or "").strip()
        else:
            text = str(item or "").strip()
        if text and text not in result:
            result.append(text[:item_limit])
        if len(result) >= limit:
            break
    return result


def _extract_json_object(text: str) -> dict[str, Any]:
    """LLM 응답 텍스트에서 JSON 객체를 찾아 파싱합니다.

    LLM이 ```json 코드블록으로 감싸거나 앞뒤 설명을 붙이는 경우도 있어,
    여러 후보 문자열을 순서대로 시도합니다.
    """

    raw = str(text or "").strip()
    if not raw:
        return {}
    fenced = re.search(r"```(?:json)?\s*(\{.*?\})\s*```", raw, flags=re.S | re.I)
    candidates = [fenced.group(1)] if fenced else []
    candidates.append(raw)
    start = raw.find("{")
    end = raw.rfind("}")
    if start >= 0 and end > start:
        candidates.append(raw[start : end + 1])
    for candidate in candidates:
        try:
            parsed = json.loads(candidate)
        except Exception:
            continue
        if isinstance(parsed, dict):
            return parsed
    return {}


def _text(value: Any) -> str:
    """Langflow Message/Data/dict 등에서 LLM 응답 텍스트를 꺼냅니다."""

    if value is None:
        return ""
    if isinstance(value, str):
        return value
    data = getattr(value, "data", None)
    if isinstance(data, dict):
        for key in ("llm_text", "text", "content", "response", "message"):
            if isinstance(data.get(key), str):
                return data[key]
    for attr in ("text", "content"):
        text = getattr(value, attr, None)
        if isinstance(text, str):
            return text
    if isinstance(value, dict):
        return json.dumps(value, ensure_ascii=False, default=str)
    return str(value)


def _payload(value: Any) -> dict[str, Any]:
    """Langflow Data/Message/dict/JSON 문자열을 일반 dict로 맞춥니다."""

    if isinstance(value, dict):
        return deepcopy(value)
    data = getattr(value, "data", None)
    if isinstance(data, dict):
        return deepcopy(data)
    text = getattr(value, "text", None) or getattr(value, "content", None)
    if isinstance(text, str) and text.strip():
        try:
            parsed = json.loads(text)
        except Exception:
            return {"text": text}
        return deepcopy(parsed) if isinstance(parsed, dict) else {"text": text}
    return {}


def _dict(value: Any) -> dict[str, Any]:
    """dict면 복사본을, 아니면 빈 dict를 반환합니다."""

    return deepcopy(value) if isinstance(value, dict) else {}


def _list(value: Any) -> list[Any]:
    """list면 복사본을, 아니면 빈 list를 반환합니다."""

    return deepcopy(value) if isinstance(value, list) else []


def _rows(value: Any) -> list[dict[str, Any]]:
    """dict row 목록만 안전하게 복사해서 반환합니다."""

    return [deepcopy(row) for row in value if isinstance(row, dict)] if isinstance(value, list) else []


def _short_text(value: Any, fallback: Any, limit: int) -> str:
    """문자열을 최대 길이로 잘라 UI가 깨지지 않게 합니다."""

    text = str(value or fallback or "").strip()
    return text[:limit]


def _choice(value: Any, allowed: set[str], fallback: Any) -> str:
    """허용된 후보 값이면 사용하고, 아니면 fallback을 사용합니다."""

    text = str(value or "").strip().lower().replace("-", "_")
    return text if text in allowed else str(fallback or "").strip().lower().replace("-", "_")


def _safe_color(value: Any) -> str:
    """`#RRGGBB` 형식의 안전한 색상 값만 통과시킵니다."""

    text = str(value or "").strip()
    return text if re.fullmatch(r"#[0-9a-fA-F]{6}", text) else ""


def _default_width(block_id: str) -> str:
    """block 종류별 기본 너비를 정합니다."""

    if block_id in {"report_header", "trend_line_chart", "grouped_bar_chart", "stacked_comparison_bar", "heatmap_matrix", "detail_data_table", "ranking_table", "outlier_exception_table", "pivot_matrix_table"}:
        return "full"
    if block_id in {"kpi_card_grid", "comparison_bar_chart", "donut_chart", "distribution_histogram", "scatter_plot", "insight_bullets"}:
        return "half"
    return "full"


def _positive_int(value: Any, default: int) -> int:
    """값을 양의 정수로 바꾸고 실패하면 default를 사용합니다."""

    try:
        parsed = int(value)
    except Exception:
        parsed = default
    return max(1, parsed)


def _bool(value: Any) -> bool:
    """문자열/숫자 형태의 boolean 값을 True/False로 해석합니다."""

    if isinstance(value, bool):
        return value
    return str(value or "").strip().lower() in {"1", "true", "yes", "y", "on"}


class LlmHtmlPlanNormalizer(Component):
    """Langflow 화면에 표시되는 03b 커스텀 컴포넌트 클래스."""

    display_name = "03b LLM 계획 검증"
    description = "LLM이 만든 리포트 계획 JSON을 검증하고 렌더러가 쓸 최종 계획으로 정리합니다."
    icon = "ShieldCheck"
    inputs = [
        DataInput(name="base_payload", display_name="기본 계획", required=True),
        MessageTextInput(name="llm_response", display_name="LLM 응답", required=True),
    ]
    outputs = [Output(name="payload_out", display_name="최종 계획", method="build_payload")]

    def build_payload(self) -> Data:
        """기본 계획과 LLM 응답을 받아 검증된 최종 계획을 출력합니다."""

        result = normalize_llm_html_plan(
            getattr(self, "base_payload", None),
            getattr(self, "llm_response", ""),
        )
        plan = result.get("report_plan", {})
        self.status = {
            "source": plan.get("plan_source"),
            "layout": plan.get("layout"),
            "blocks": [block.get("block_id") for block in plan.get("blocks", [])],
        }
        return Data(data=result)

from __future__ import annotations

"""05-1 HTML 원문 출력 노드.

이 파일은 Report API 서버를 쓰지 않는 경우를 위한 마지막 노드입니다.
04번 렌더러가 만든 HTML 전체 코드를 Playground 답변 영역에 그대로 출력합니다.
"""

import json
from copy import deepcopy
from typing import Any

from lfx.custom.custom_component.component import Component
from lfx.io import DataInput, Output
from lfx.schema.message import Message


def build_html_source_message(payload_value: Any) -> str:
    """payload에서 HTML 원문을 꺼내 markdown 코드블록 형태의 메시지로 만듭니다."""

    payload = _payload(payload_value)
    html_report = _dict(payload.get("html_report"))
    html = str(html_report.get("html") or "")
    if not html.strip():
        return "HTML 원문이 비어 있습니다. 04 HTML 렌더링의 HTML 생성 결과를 05-1의 HTML 생성 결과 입력에 연결하세요."
    return f"````html\n{html.rstrip()}\n````"


def _payload(value: Any) -> dict[str, Any]:
    """Langflow Data/Message/dict/JSON 문자열을 일반 dict로 맞춥니다."""

    if isinstance(value, dict):
        return deepcopy(value)
    data = getattr(value, "data", None)
    if isinstance(data, dict):
        return deepcopy(data)
    text = getattr(value, "text", None) or getattr(value, "content", None)
    if isinstance(text, str) and text.strip():
        try:
            parsed = json.loads(text)
        except Exception:
            return {"text": text}
        return deepcopy(parsed) if isinstance(parsed, dict) else {"text": text}
    return {}


def _dict(value: Any) -> dict[str, Any]:
    """dict면 복사본을, 아니면 빈 dict를 반환합니다."""

    return deepcopy(value) if isinstance(value, dict) else {}


class HtmlSourceOutput(Component):
    """Langflow 화면에 표시되는 05-1 커스텀 컴포넌트 클래스."""

    display_name = "05-1 HTML 원문 출력"
    description = "Report API 없이 04에서 생성된 전체 HTML 코드를 Playground에 그대로 출력합니다."
    icon = "Code2"
    inputs = [DataInput(name="payload", display_name="HTML 생성 결과", required=True)]
    outputs = [Output(name="html_message", display_name="HTML 원문", method="build_message")]

    def build_message(self) -> Message:
        """Playground에 보여줄 HTML 원문 메시지를 생성합니다."""

        text = build_html_source_message(getattr(self, "payload", None))
        self.status = {"html_chars": len(text)}
        return Message(text=text)

